function f(e){return new Date(e).toLocaleDateString("es-BO",{weekday:"long",day:"numeric",month:"long",timeZone:"America/La_Paz"})}function c(e){return new Date(e).toLocaleTimeString("es-BO",{hour:"2-digit",minute:"2-digit",hour12:!1,timeZone:"America/La_Paz"})}function s(e){const t=new Date,o=new Date(e),a=t-o,n=Math.floor(a/6e4),i=Math.floor(a/36e5),r=Math.floor(a/864e5);return n<1?"ahora":n<60?`hace ${n} min`:i<24?`hace ${i}h`:r<7?`hace ${r}d`:o.toLocaleDateString("es-BO",{day:"numeric",month:"short",timeZone:"America/La_Paz"})}export{s as a,f as b,c as f};
